import React from 'react';
import { BrowserRouter as Router, Routes, Route, useLocation, Navigate } from 'react-router-dom';

// Import Components
import Sidebar from './components/Sidebar';

// Import Pages
import Login from './pages/Login';
import Register from './pages/Register';
import Dashboard from './pages/Dashboard';
import Explore from './pages/Explore';
import BarterChat from './pages/BarterChat';
import Notifications from './pages/Notifications';
import Profile from './pages/Profile';
import Settings from './pages/Settings';
import CreateListing from './pages/CreateListing';
import History from './pages/History';

// This wrapper component handles the Sidebar visibility logic
function AppLayout() {
  const location = useLocation();
  
  // Define which paths should NOT show the sidebar
  const authPaths = ['/login', '/register', '/'];
  const hideSidebar = authPaths.includes(location.pathname);

  return (
    <div className="flex bg-slate-50 min-h-screen">
      {/* Sidebar only shows if we are not on an Auth page */}
      {!hideSidebar && <Sidebar />}
      
      <main className="flex-1 overflow-y-auto">
        <Routes>
          {/* Default path redirects to Login */}
          <Route path="/" element={<Navigate to="/login" />} />
          
          {/* Auth Pages */}
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />

          {/* Main App Pages */}
          <Route path="/dashboard" element={<Dashboard />} />
          <Route path="/explore" element={<Explore />} />
          <Route path="/messages" element={<BarterChat />} />
          <Route path="/notifications" element={<Notifications />} />
          <Route path="/profile" element={<Profile />} />
          <Route path="/settings" element={<Settings />} />
          <Route path="/create" element={<CreateListing />} />
          <Route path="/history" element={<History />} />
        </Routes>
      </main>
    </div>
  );
}

export default function App() {
  return (
    <Router>
      <AppLayout />
    </Router>
  );
}
